export type KP_ModifierStateValue=0|1|2;
export type KP_ModifierState=Record<KP_ModifierKeys,KP_ModifierStateValue>;
export const modifierState={} as KP_ModifierState, mLock={
    sym:1
} as Record<KP_ModifierKeys, undefined|0|1>;
export const modifierKeys={"shift":1,"ctrl":1,"edit":1,"sym":1,"select":1};
export type KP_ModifierKeys=keyof typeof modifierKeys;
export type LockType=
    "single"/*locks on single tap*/|
    "double"/*locks on double tap*/|
    "none"/*never locked*/;
export type Datas={
    modifier?: KP_ModifierKeys,
    lock?:LockType,
    "modifier-off"?:KP_ModifierKeys,
    command?: string,
    text?: string,
    keycode?: string,
    key?:string,
    ctrl?:string,
};